 1	import { Popover, ProgressStep, ProgressStepper } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { FlowScope } from '../../model/flow-query';
 4	import { ScopeConfigDef } from '../../model/scope';
 5	import './scope-slider.css';
 6	
 7	export interface ScopeSliderProps {
 8	  scope: FlowScope;
 9	  setScope: (ms: FlowScope) => void;
10	  scopeDefs: ScopeConfigDef[];
11	}
12	
13	export const ScopeSlider: React.FC<ScopeSliderProps> = ({ scope, setScope, scopeDefs }) => {
14	  return (
15	    <ProgressStepper isVertical isCenterAligned>
16	      {scopeDefs.map((sd, i) => (
17	        <ProgressStep
18	          key={`scope-step-${i}`}
19	          id={`scope-step-${i}`}
20	          variant={sd.id === scope ? 'info' : 'pending'}
21	          isCurrent={sd.id === scope}
22	          onClick={() => setScope(sd.id)}
23	          popoverRender={stepRef => (
24	            <Popover
25	              headerContent={<div>{sd.name}</div>}
26	              bodyContent={<div>{sd.description}</div>}
27	              triggerRef={stepRef}
28	              position="right"
29	            />
30	          )}
31	        >
32	          {sd.name}
33	        </ProgressStep>
34	      ))}
35	    </ProgressStepper>
36	  );
37	};

